hooks.onDraw:
const s = world.state;
const A = function (v) { return Math.max(0, Math.min(1, v || 0)); };
const PJS = ' "Plus Jakarta Sans", ui-sans-serif, system-ui';
const TAU = Math.PI * 2;
const T = world.t || 0;
const NB = { x: 460, y: 380 };
const o1 = A(s.out1), o2 = A(s.out2), o3 = A(s.out3);
// líneas-pipeline del cuaderno a cada formato (cian punteado)
const hubs = [ { x: 185, a: o1, ty: 222 }, { x: 452, a: o2, ty: 182 }, { x: 628, a: o3, ty: 202 } ];
for (const h of hubs) {
  if (h.a < 0.02) continue;
  world.draw.arrow(NB.x, NB.y, h.x, h.ty, { color: '#4fd0e0', alpha: h.a * 0.55, width: 1.6, dash: [5, 5], head: 0, curve: (h.x - NB.x) * 0.08 });
}
// ===== AUDIO =====
if (o1 > 0.01) {
  ctx.save(); ctx.globalAlpha = o1;
  const x = 185, y = 190, w = 152, h = 86, L = x - w / 2, Tp = y - h / 2;
  world.draw.rrect(L, Tp, w, h, 8); ctx.fillStyle = 'rgba(20,26,48,0.95)'; ctx.fill();
  world.draw.rrect(L, Tp, w, h, 8); ctx.lineWidth = 1.4; ctx.strokeStyle = 'rgba(79,208,224,0.55)'; ctx.stroke();
  ctx.font = '700 10px' + PJS; ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.fillStyle = '#F4AC1D'; ctx.fillText('AUDIO', L + 12, Tp + 9);
  const sx = L + 24, sy = y + 4;
  ctx.fillStyle = '#cfe8ee';
  ctx.beginPath(); ctx.moveTo(sx - 6, sy - 5); ctx.lineTo(sx - 1, sy - 5); ctx.lineTo(sx + 5, sy - 11); ctx.lineTo(sx + 5, sy + 11); ctx.lineTo(sx - 1, sy + 5); ctx.lineTo(sx - 6, sy + 5); ctx.closePath(); ctx.fill();
  ctx.strokeStyle = '#4fd0e0'; ctx.lineWidth = 1.6;
  ctx.beginPath(); ctx.arc(sx + 5, sy, 9, -0.7, 0.7); ctx.stroke();
  ctx.beginPath(); ctx.arc(sx + 5, sy, 14, -0.6, 0.6); ctx.stroke();
  ctx.fillStyle = '#4fd0e0';
  const bx = L + 54, bw = 3, gap = 4;
  for (let i = 0; i < 9; i++) { const hh = 4 + 11 * Math.abs(Math.sin(T * 4 + i * 0.7)); ctx.fillRect(bx + i * (bw + gap), y + 4 - hh / 2, bw, hh); }
  const v1 = 0.5 + 0.5 * Math.sin(T * 3), v2 = 0.5 + 0.5 * Math.sin(T * 3 + Math.PI);
  ctx.fillStyle = 'rgba(244,172,29,' + (0.35 + 0.6 * v1) + ')'; ctx.beginPath(); ctx.arc(L + w - 24, y + 2, 4, 0, TAU); ctx.fill();
  ctx.fillStyle = 'rgba(244,172,29,' + (0.35 + 0.6 * v2) + ')'; ctx.beginPath(); ctx.arc(L + w - 13, y + 2, 4, 0, TAU); ctx.fill();
  ctx.font = '500 9px' + PJS; ctx.fillStyle = '#9aa6c8'; ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic'; ctx.fillText('voces · diálogo', x, Tp + h - 9);
  ctx.restore();
}
// ===== GUÍA DE ESTUDIO =====
if (o2 > 0.01) {
  ctx.save(); ctx.globalAlpha = o2;
  const x = 452, y = 138, w = 158, h = 92, L = x - w / 2, Tp = y - h / 2;
  world.draw.rrect(L, Tp, w, h, 8); ctx.fillStyle = 'rgba(20,26,48,0.95)'; ctx.fill();
  world.draw.rrect(L, Tp, w, h, 8); ctx.lineWidth = 1.4; ctx.strokeStyle = 'rgba(244,172,29,0.5)'; ctx.stroke();
  ctx.font = '700 10px' + PJS; ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.fillStyle = '#F4AC1D'; ctx.fillText('GUÍA DE ESTUDIO', L + 12, Tp + 9);
  const shades = ['#e6dcc4', '#ede3cb', '#f3ead5'];
  const cw = 44, ch = 32, cyc = y + 8;
  for (let k = 2; k >= 0; k--) { const ox = L + 16 + k * 4, oy = cyc - k * 3; world.draw.rrect(ox, oy - ch / 2, cw, ch, 4); ctx.fillStyle = shades[k]; ctx.fill(); }
  ctx.fillStyle = '#F4AC1D'; ctx.fillRect(L + 24, cyc - 9, 28, 3);
  ctx.fillStyle = '#6E7896'; ctx.fillRect(L + 24, cyc - 2, 24, 2); ctx.fillRect(L + 24, cyc + 3, 28, 2); ctx.fillRect(L + 24, cyc + 8, 16, 2);
  for (let i = 0; i < 3; i++) { const ry = cyc - 9 + i * 9; ctx.fillStyle = '#4fd0e0'; ctx.beginPath(); ctx.arc(L + 100, ry, 1.8, 0, TAU); ctx.fill(); ctx.fillStyle = '#9aa6c8'; ctx.fillRect(L + 106, ry - 1.2, 36, 2.4); }
  ctx.font = '500 9px' + PJS; ctx.fillStyle = '#9aa6c8'; ctx.textAlign = 'center'; ctx.textBaseline = 'alphabetic'; ctx.fillText('resúmenes · tarjetas', x, Tp + h - 9);
  ctx.restore();
}
// ===== MAPA MENTAL (clímax): árbol con raíz a la izquierda, ramas a la derecha =====
if (o3 > 0.01) {
  ctx.save();
  const rootX = 628, rootY = 176, ex = rootX + 29;
  const kids = [ { x: 792, y: 106, t: 'idea' }, { x: 814, y: 152, t: 'ejemplo' }, { x: 814, y: 200, t: 'dato' }, { x: 792, y: 246, t: 'duda' } ];
  // 1) ramas curvas que nacen del borde derecho de la raíz (sin punta)
  kids.forEach(function (k, i) {
    const ka = A((o3 - 0.10 - i * 0.15) / 0.2); if (ka < 0.02) return;
    ctx.save(); ctx.globalAlpha = o3 * ka;
    world.draw.arrow(ex, rootY, k.x, k.y, { color: '#4fd0e0', width: 1.8, alpha: 0.85, head: 0, curve: (k.y - rootY) * 0.18 });
    ctx.restore();
  });
  // 2) nodos hijos opacos (tapan el extremo de cada rama)
  kids.forEach(function (k, i) {
    const ka = A((o3 - 0.10 - i * 0.15) / 0.2); if (ka < 0.02) return;
    ctx.save(); ctx.globalAlpha = o3 * ka;
    world.draw.node(k.x, k.y, 56, 24, { fill: '#1F2547', stroke: '#9aa6c8', strokeWidth: 1.2, radius: 6, label: k.t, labelColor: '#cfe8ee', font: '600 9px' + PJS });
    ctx.restore();
  });
  // 3) raíz encima de todas las ramas
  ctx.save(); ctx.globalAlpha = o3;
  world.draw.node(rootX, rootY, 58, 30, { fill: '#3a5a8c', stroke: '#4fd0e0', strokeWidth: 1.8, radius: 7, label: 'Tema', labelColor: '#FBFAF6', font: '700 11px' + PJS });
  ctx.font = '700 10px' + PJS; ctx.fillStyle = '#F4AC1D'; ctx.textAlign = 'center'; ctx.textBaseline = 'top'; ctx.fillText('MAPA MENTAL', 716, 268);
  ctx.restore();
  ctx.restore();
}
// ===== learners (el motor delega su dibujo al onDraw) =====
const ls = world.entities.filter(function (e) { return e.type === 'learner'; });
ls.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (const e of ls) world.draw.learner(e);
